31	namespace NPOI.XSSF.UserModel
32	{
33	    public class XSSFColumn : IColumn, IComparable<XSSFColumn>
34	    {
35	        #region Private properties
36	        private static readonly POILogger _logger =
37	            POILogFactory.GetLogger(typeof(XSSFColumn));
38	
39	        /// <summary>
40	        /// the xml node Containing defInition for this column
41	        /// </summary>
42	        private readonly CT_Col _column;
43	
44	        /// <summary>
45	        /// the parent sheet
46	        /// </summary>
47	        private readonly XSSFSheet _sheet;
48	
49	        private readonly StylesTable _stylesSource;
50	        #endregion
51	
52	        #region Public properties
53	        /// <summary>
54	        /// XSSFSheet this column belongs to
55	        /// </summary>
56	        public ISheet Sheet
57	        {
58	            get
59	            {
60	                return _sheet;
61	            }
62	        }
63	
64	        /// <summary>
65	        /// Get the number of the first cell Contained in this column.
66	        /// </summary>
67	        /// <returns>short representing the first logical cell in the column,
68	        /// or -1 if the column does not contain any cells.</returns>
69	        public short FirstCellNum
70	        {
71	            get
72	            {
73	                return (short)(Cells.Count == 0 ? -1 : GetFirstKey());
74	            }
75	        }
76	
77	        /// <summary>
78	        /// Gets the index of the last cell Contained in this column <b>PLUS 
79	        /// ONE</b>. The result also happens to be the 1-based row number of 
80	        /// the last cell. This value can be used as a standard upper bound 
81	        /// when iterating over cells:
82	        /// </summary>
83	        /// <returns>short representing the last logical cell in the column 
84	        /// <b>PLUS ONE</b>, or -1 if the column does not contain any cells.</returns>
85	        public short LastCellNum
86	        {
87	            get
88	            {
89	                return (short)(Cells.Count == 0 ? -1 : GetLastKey() + 1);
90	            }
91	        }
92	
93	        /// <summary>
94	        /// Get the column's width. 
95	        /// If the width is not Set, the default worksheet value is returned,
96	        /// See <see cref="XSSFSheet.DefaultColumnWidth"/>
97	        /// </summary>
98	        /// <returns>column width</returns>
99	        public double Width
100	        {
101	            get
102	            {
103	                return _column.width == 0
104	                    ? _sheet.DefaultColumnWidth
105	                    : _column.width;
106	            }
107	
108	            set
109	            {
110	                if (value < 0)
111	                {
112	                    if (_column.IsSetWidth())
113	                    {
114	                        _column.UnsetWidth();
115	                    }
116	
117	                    if (_column.IsSetCustomWidth())
118	                    {
119	                        _column.UnsetCustomWidth();
120	                    }
121	                }
122	                else
123	                {
124	                    _column.width = value;
125	                    _column.customWidth = true;
126	
127	                }
128	            }
129	        }
130	
131	        /// <summary>
132	        /// Gets the number of defined cells (NOT number of cells in the actual
133	        /// column!). That is to say if only rows 0,4,5 have values then 
134	        /// there would be 3.
135	        /// </summary>
136	        /// <returns>int representing the number of defined cells in the column.</returns>
137	        public int PhysicalNumberOfCells
138	        {
139	            get
140	            {
141	                return Cells.Count;
142	            }
143	        }
144	
145	        /// <summary>
146	        /// Get column number this column represents
147	        /// </summary>
148	        /// <returns>the column number (0 based)</returns>
149	        public int ColumnNum
150	        {
151	            get
152	            {
153	                return (int)_column.min - 1;
154	            }
155	
156	            set
157	            {
158	                int maxColumn = SpreadsheetVersion.EXCEL2007.LastColumnIndex;
159	                if (value < 0 || value > maxColumn)
160	                {
161	                    throw new ArgumentException("Invalid column number (" + value
162	                            + ") outside allowable range (0.." + maxColumn + ")");
163	                }
164	
165	                // As current implementation of XSSFColumn is breaking CT_Col 
166	                // objects that span over multiple columns into individual
167	                // columns we need to set min and max values to the same value.
168	                _column.min = (uint)(value + 1);
169	                _column.max = (uint)(value + 1);
170	            }
171	        }
172	
173	        /// <summary>
174	        /// Get whether or not to display this column with 0 width
175	        /// </summary>
176	        public bool ZeroWidth
177	        {
178	            get
179	            {
180	                return _column.hidden;
181	            }
182	
183	            set
184	            {
185	                _column.hidden = value;
186	            }
187	        }
188	
189	        /// <summary>
190	        /// Is this column formatted? Most aren't, but some columns
191	        /// do have whole-column styles. For those that do, you
192	        /// can get the formatting from <see cref="ColumnStyle"/>
193	        /// </summary>
194	        public bool IsFormatted
195	        {
196	            get
197	            {
198	                return _column.IsSetStyle();
199	            }
200	        }
201	
202	        /// <summary>
203	        /// Is the column width set to best fit the content?
204	        /// </summary>
205	        public bool IsBestFit
206	        {
207	            get
208	            {
209	                return _column.bestFit;
210	            }
211	
212	            set
213	            {
214	                _column.bestFit = value;
215	            }
216	        }
217	
218	        /// <summary>
219	        /// Returns the whole-column cell style. Most columns won't
220	        /// have one of these, so will return null. Call
221	        /// <see cref="IsFormatted"/> to check first.
222	        /// </summary>
223	        public ICellStyle ColumnStyle
224	        {
225	            get
226	            {
227	                return IsFormatted
228	                    && _stylesSource != null
229	                    && _stylesSource.NumCellStyles > 0
230	                    ? _stylesSource.GetStyleAt((int)_column.style)
231	                    : (ICellStyle)null;
232	            }
233	
234	            set
235	            {
236	                if (value == null)
237	                {
238	                    if (_column.IsSetStyle())
239	                    {
240	                        _column.UnsetStyle();
241	                    }
242	                }
243	                else
244	                {
245	                    XSSFCellStyle xStyle = (XSSFCellStyle)value;
246	                    xStyle.VerifyBelongsToStylesSource(_stylesSource);
247	
248	                    long idx = _stylesSource.PutStyle(xStyle);
249	                    _column.style = (uint)idx;
250	                }
251	
252	                foreach (ICell cell in Cells)
253	                {
254	                    cell.CellStyle = value;
255	                }
256	            }
257	        }
258	
259	        public List<ICell> Cells
260	        {
261	            get
262	            {
263	                List<ICell> cells = new List<ICell>();
264	
265	                foreach (IRow row in _sheet.Cast<IRow>())
266	                {
267	                    foreach (ICell cell in row.Where(c => c.ColumnIndex == ColumnNum))
268	                    {
269	                        cells.Add(cell);
270	                        _sheet.OnReadCell((XSSFCell)cell);
271	                    }
272	                }
273	
274	                return cells;
275	            }
276	        }
277	
278	        public int OutlineLevel
279	        {
280	            get
281	            {
282	                return _column.outlineLevel;
283	            }
284	
285	            set
286	            {
287	                _column.outlineLevel = (byte)value;
288	            }
289	        }
290	
291	        public bool Hidden
292	        {
293	            get
294	            {
295	                return _column.hidden;
296	            }
297	
298	            set
299	            {
300	                _column.hidden = value;
301	            }
302	        }
303	
304	        public bool Collapsed
305	        {
306	            get
307	            {
308	                return _column.collapsed;
309	            }
310	
311	            set
312	            {
313	                _column.collapsed = value;
314	            }
315	        }
316	        #endregion
317	
318	        #region Constructor
319	        /// <summary>
320	        /// Construct an XSSFColumn.
321	        /// </summary>
322	        /// <param name="column">the xml node Containing defInitions for this column.</param>
323	        /// <param name="sheet">the parent sheet.</param>
324	        public XSSFColumn(CT_Col column, XSSFSheet sheet)
325	        {
326	            _column = column;
327	            _sheet = sheet;
328	
329	            if (!column.IsSetNumber())
330	            {
331	                // Certain file format writers skip the column number
332	                // Assume no gaps, and give this the next column number
333	                int nextColumnNum = sheet.LastColumnNum + 2;
334	                if (nextColumnNum == 2 && sheet.PhysicalNumberOfColumns == 0)
335	                {
336	                    nextColumnNum = 1;
337	                }
338	
339	                // As current implementation of XSSFColumn is breaking CT_Col 
340	                // objects that span over multiple columns into individual
341	                // columns we need to set min and max values to the same value.
342	                _column.min = (uint)nextColumnNum + 1;
343	                _column.max = (uint)nextColumnNum + 1;
344	            }
345	
346	            _stylesSource = ((XSSFWorkbook)sheet.Workbook).GetStylesSource();
347	        }
348	        #endregion
349	
350	        #region Public methods
351	        /// <summary>
352	        /// Use this to create new cells within the column and return it. The 
353	        /// cell that is returned is a <see cref="CellType.Blank"/>. The type 
354	        /// can be Changed either through calling 
355	        /// <see cref="ICell.SetCellValue"/> or <see cref="ICell.SetCellType"/>.
356	        /// </summary>
357	        /// <param name="rowIndex">the row number this cell represents</param>
358	        /// <returns>a high level representation of the Created cell</returns>
359	        /// <exception cref="ArgumentOutOfRangeException">if columnIndex is 
360	        /// less than 0 or greater than 16384, the maximum number of columns 
361	        /// supported by the SpreadsheetML format(.xlsx)</exception>
362	        public ICell CreateCell(int rowIndex)
363	        {
364	            return CreateCell(rowIndex, CellType.Blank);
365	        }
366	
367	        /// <summary>
368	        /// Use this to create new cells within the column and return it.
369	        /// </summary>
370	        /// <param name="rowIndex">the row number this cell represents</param>
371	        /// <param name="type">the cell's data type</param>
372	        /// <returns>a high level representation of the Created cell.</returns>
373	        /// <exception cref="ArgumentOutOfRangeException">if columnIndex is 
374	        /// less than 0 or greater than 16384, the maximum number of columns 
375	        /// supported by the SpreadsheetML format(.xlsx)</exception>
376	        public ICell CreateCell(int rowIndex, CellType type)
377	        {
378	            if (rowIndex > SpreadsheetVersion.EXCEL2007.LastRowIndex ||
379	                rowIndex < 0)
380	            {
381	                throw new ArgumentOutOfRangeException(
382	                    "Row index should be between 0 and " +
383	                    SpreadsheetVersion.EXCEL2007.LastRowIndex + ". Input was " +
384	                    rowIndex);
385	            }
386	
387	            ValidateCellType(type);
388	
389	            IRow row = Sheet.GetRow(rowIndex) ?? Sheet.CreateRow(rowIndex);
390	            ICell newCell = row.CreateCell(ColumnNum, type);
391	
392	            if (IsFormatted)
393	            {
394	                newCell.CellStyle = ColumnStyle;
395	            }
396	
397	            return newCell;
398	        }
399	
400	        /// <summary>
401	        /// Returns the cell at the given (0 based) index,
402	        /// with the <see cref="MissingCellPolicy"/> from the parent Workbook.
403	        /// </summary>
404	        /// <param name="cellNum"></param>
405	        /// <returns>the cell at the given (0 based) index</returns>
406	        public ICell GetCell(int cellNum)
407	        {
408	            return GetCell(cellNum, _sheet.Workbook.MissingCellPolicy);
409	        }
410	
411	        /// <summary>
412	        /// Returns the cell at the given (0 based) index, with the specified 
413	        /// <see cref="MissingCellPolicy"/>
414	        /// </summary>
415	        /// <param name="cellNum"></param>
416	        /// <param name="policy"></param>
417	        /// <returns>the cell at the given (0 based) index</returns>
418	        /// <exception cref="ArgumentException">if cellnum is less than 0 or 
419	        /// the specified MissingCellPolicy is invalid</exception>
420	        public ICell GetCell(int cellNum, MissingCellPolicy policy)
421	        {
422	            if (cellNum < 0 || cellNum > SpreadsheetVersion.EXCEL2007.LastRowIndex)
423	            {
424	                throw new ArgumentOutOfRangeException(
425	                    "Cell number should be between 0 and " +
426	                    SpreadsheetVersion.EXCEL2007.LastRowIndex + ". Input was " +
427	                    cellNum);
428	            }
429	
430	            XSSFCell cell = (XSSFCell)RetrieveCell(cellNum);
431	
432	            switch (policy)
433	            {
434	                case MissingCellPolicy.RETURN_NULL_AND_BLANK:
435	                    return cell;
436	                case MissingCellPolicy.RETURN_BLANK_AS_NULL:
437	                    bool isBlank = cell != null && cell.CellType == CellType.Blank;
438	                    return isBlank ? null : cell;
439	                case MissingCellPolicy.CREATE_NULL_AS_BLANK:
440	                    return cell ?? CreateCell(cellNum, CellType.Blank);
441	                default:
442	                    throw new ArgumentException("Illegal policy " + policy + " (" + policy + ")");
443	            }
444	        }
445	
446	        /// <summary>
447	        /// Remove the Cell from this column.
448	        /// </summary>
449	        /// <param name="cell">the cell to remove</param>
450	        /// <exception cref="ArgumentException"></exception>
451	        public void RemoveCell(ICell cell)
452	        {
453	            if (cell == null)
454	            {
455	                throw new ArgumentException("Cell can not be null");
456	            }
457	
458	            if (cell.ColumnIndex != ColumnNum)
459	            {
460	                throw new ArgumentException("Specified cell does not belong " +
461	                    "to this column");
462	            }
463	
464	            IRow row = _sheet.GetRow(cell.RowIndex);
465	
466	            row.RemoveCell(cell);
467	        }
468	
469	        /// <summary>
470	        /// Copy the cells from srcColumn to this column If this column is not 
471	        /// a blank column, this will merge the two columns, overwriting the 
472	        /// cells in this column with the cells in srcColumn If srcColumn is 
473	        /// null, overwrite cells in destination column with blank values, 
474	        /// styles, etc per cell copy policy srcColumn may be from a different 
475	        /// sheet in the same workbook
476	        /// </summary>
477	        /// <param name="srcColumn">the column to copy from</param>
478	        /// <param name="policy">the policy to determine what gets copied</param>
479	        public void CopyColumnFrom(IColumn srcColumn, CellCopyPolicy policy)
480	        {
481	            if (srcColumn == null)
482	            {
483	                // srcColumn is blank. Overwrite cells with blank values,
484	                // blank styles, etc per cell copy policy
485	                foreach (ICell destCell in this)
486	                {
487	                    XSSFCell srcCell = null;
488	
489	                    ((XSSFCell)destCell).CopyCellFrom(srcCell, policy);
490	                }
491	
492	                if (policy.IsCopyMergedRegions)
493	                {
494	                    // Remove MergedRegions in dest column
495	                    int destColumnNum = ColumnNum;
496	                    int index = 0;
497	                    HashSet<int> indices = new HashSet<int>();
498	                    foreach (CellRangeAddress destRegion in Sheet.MergedRegions)
499	                    {
500	                        if (destColumnNum == destRegion.FirstColumn
501	                            && destColumnNum == destRegion.LastColumn)
502	                        {
503	                            _ = indices.Add(index);
504	                        }
505	
506	                        index++;
507	                    }
508	
509	                    (Sheet as XSSFSheet).RemoveMergedRegions(indices.ToList());
510	                }
511	
512	                if (policy.IsCopyColumnWidth)
513	                {
514	                    // clear row height
515	                    Width = -1;
516	                }
517	            }
518	            else
519	            {
520	                foreach (ICell c in srcColumn)
521	                {
522	                    XSSFCell srcCell = (XSSFCell)c;
523	                    XSSFCell destCell =
524	                        CreateCell(srcCell.RowIndex, srcCell.CellType) as XSSFCell;
525	                    destCell.CopyCellFrom(srcCell, policy);
526	                }
527	
528	                XSSFColumnShifter columnShifter = new XSSFColumnShifter(_sheet);
529	                int sheetIndex = _sheet.Workbook.GetSheetIndex(_sheet);
530	                string sheetName = _sheet.Workbook.GetSheetName(sheetIndex);
531	                int srcColumnNum = srcColumn.ColumnNum;
532	                int destColumnNum = ColumnNum;
533	                int columnDifference = destColumnNum - srcColumnNum;
534	                FormulaShifter shifter = FormulaShifter.CreateForColumnCopy(
535	                    sheetIndex,
536	                    sheetName,
537	                    srcColumnNum,
538	                    srcColumnNum,
539	                    columnDifference,
540	                    SpreadsheetVersion.EXCEL2007);
541	                columnShifter.UpdateColumnFormulas(this, shifter);
542	
543	                if (policy.IsCopyMergedRegions)
544	                {
545	                    foreach (CellRangeAddress srcRegion in srcColumn.Sheet.MergedRegions)
546	                    {
547	                        if (srcColumnNum == srcRegion.FirstColumn
548	                            && srcColumnNum == srcRegion.LastColumn)
549	                        {
550	                            CellRangeAddress destRegion = srcRegion.Copy();
551	                            destRegion.FirstColumn = destColumnNum;
552	                            destRegion.LastColumn = destColumnNum;
553	                            _ = Sheet.AddMergedRegion(destRegion);
554	                        }
555	                    }
556	                }
557	
558	                if (policy.IsCopyColumnWidth)
559	                {
560	                    Width = srcColumn.Width;
561	                }
562	            }
563	        }
564	
565	        public void MoveCell(ICell cell, int newColumn)
566	        {
567	            throw new NotImplementedException();
568	        }
569	
570	        public IColumn CopyColumnTo(int targetIndex)
571	        {
572	            return ((XSSFSheet)Sheet).CopyColumn(ColumnNum, targetIndex);
573	        }
574	
575	        public ICell CopyCell(int sourceIndex, int targetIndex)
576	        {
577	            return CellUtil.CopyCell(this, sourceIndex, targetIndex);
578	        }
