585	        /// <summary>
586	        /// Returns the underlying CT_Col xml node Containing all cell 
587	        /// defInitions in this column
588	        /// </summary>
589	        /// <returns>the underlying CT_Col xml node</returns>
590	        public CT_Col GetCTCol()
591	        {
592	            return _column;
593	        }
594	        #endregion
