596	        #region Internal methods
597	        /// <summary>
598	        /// update cell references when Shifting columns
599	        /// </summary>
600	        /// <param name="n">n the number of columns to move</param>
601	        internal void Shift(int n)
602	        {
603	            int columnNum = ColumnNum + n;
604	            CalculationChain calcChain =
605	                ((XSSFWorkbook)_sheet.Workbook).GetCalculationChain();
606	            int sheetId = (int)_sheet.sheet.sheetId;
607	            string msg = "Column[columnNum=" + ColumnNum + "] contains cell(s) " +
608	                "included in a multi-cell array formula. You cannot change " +
609	                "part of an array.";
610	
611	            foreach (ICell c in this)
612	            {
613	                XSSFCell cell = (XSSFCell)c;
614	
615	                if (cell.IsPartOfArrayFormulaGroup)
616	                {
617	                    cell.NotifyArrayFormulaChanging(msg);
618	                }
619	
620	                //remove the reference in the calculation chain
621	                calcChain?.RemoveItem(sheetId, cell.GetReference());
622	
623	                CT_Cell ctCell = cell.GetCTCell();
624	                string r = new CellReference(cell.RowIndex, columnNum)
625	                    .FormatAsString();
626	                ctCell.r = r;
627	                cell.ColumnIndex = columnNum;
628	            }
629	
630	            ColumnNum = columnNum;
631	        }
632	
633	        /// <summary>
634	        /// Fired when the document is written to an output stream.
635	        /// See <see cref="XSSFSheet.Write"/>
636	        /// </summary>
637	        internal static void OnDocumentWrite()
638	        {
639	
640	        }
641	        #endregion
642	
643	        #region IEnumerable and IComparable members
644	        /// <summary>
645	        /// Cell iterator over the physically defined cell
646	        /// </summary>
647	        /// <returns>an iterator over cells in this column.</returns>
648	        public List<ICell>.Enumerator CellIterator()
649	        {
650	            return Cells.GetEnumerator();
651	        }
652	
653	        /// <summary>
654	        /// Alias for <see cref="CellIterator"/> to allow  foreach loops
655	        /// </summary>
656	        /// <returns>an iterator over cells in this row.</returns>
657	        public IEnumerator<ICell> GetEnumerator()
658	        {
659	            return CellIterator();
660	        }
661	
662	        /// <summary>
663	        /// Compares two <see cref="XSSFColumn"/> objects. Two columns are 
664	        /// equal if they belong to the same worksheet and their column indexes
665	        /// are equal.
666	        /// </summary>
667	        /// <param name="other">the <see cref="XSSFColumn"/> to be compared.</param>
668	        /// <returns>
669	        /// the value 0 if the column number of this <see cref="XSSFColumn"/> 
670	        /// is equal to the column number of the argument <see cref="XSSFColumn"/> 
671	        /// a value less than 0 if the column number of this this 
672	        /// <see cref="XSSFColumn"/> is numerically less than the column number
673	        /// of the argument <see cref="XSSFColumn"/> a value greater than 0 if
674	        /// the column number of this this <see cref="XSSFColumn"/> is 
675	        /// numerically greater than the column number of the 
676	        /// argument <see cref="XSSFColumn"/>
677	        /// </returns>
678	        /// <exception cref="ArgumentException">if the argument column belongs 
679	        /// to a different worksheet</exception>
680	        public int CompareTo(XSSFColumn other)
681	        {
682	            return Sheet != other.Sheet
683	                ? throw new ArgumentException(
684	                    "The compared columns must belong to the same sheet")
685	                : ColumnNum.CompareTo(other.ColumnNum);
686	        }
687	
688	        public override bool Equals(object obj)
689	        {
690	            return obj is XSSFColumn other
691	                && ColumnNum == other.ColumnNum
692	                && Sheet == other.Sheet;
693	        }
694	
695	        public override int GetHashCode()
696	        {
697	            return _column.GetHashCode();
698	        }
699	        #endregion
