using NPOI.SS.UserModel;
using NPOI.XSSF.UserModel;
using NUnit.Framework;

namespace TestCases.XSSF.UserModel
{
    [TestFixture]
    public class TestXSSFSheetDefaultColumnStyle
    {
        [Test]
        public void TestDefaultColumnStyleAppliedToNewCells()
        {
            IWorkbook wb = new XSSFWorkbook();
            ISheet sheet = wb.CreateSheet("test");

            // Create a style with a specific fill color
            ICellStyle defaultStyle = wb.CreateCellStyle();
            defaultStyle.FillForegroundColor = IndexedColors.Red.Index;
            defaultStyle.FillPattern = FillPattern.SolidForeground;

            // Set the default column style for column 0
            sheet.SetDefaultColumnStyle(0, defaultStyle);

            // Create a row and a cell in column 0 via the row API
            IRow row = sheet.CreateRow(0);
            ICell cell = row.CreateCell(0);

            // The cell should have the default column style applied
            ClassicAssert.IsNotNull(cell.CellStyle,
                "Cell style should not be null when column has a default style");
            ClassicAssert.AreEqual(IndexedColors.Red.Index,
                cell.CellStyle.FillForegroundColor,
                "Cell should inherit the column's default fill foreground color");

            wb.Close();
        }

        [Test]
        public void TestDefaultColumnStyleAppliedToNewCellsMultipleColumns()
        {
            IWorkbook wb = new XSSFWorkbook();
            ISheet sheet = wb.CreateSheet("test");

            // Create styles
            ICellStyle style1 = wb.CreateCellStyle();
            style1.FillForegroundColor = IndexedColors.Red.Index;
            style1.FillPattern = FillPattern.SolidForeground;

            ICellStyle style2 = wb.CreateCellStyle();
            style2.FillForegroundColor = IndexedColors.Blue.Index;
            style2.FillPattern = FillPattern.SolidForeground;

            // Set default column styles
            sheet.SetDefaultColumnStyle(0, style1);
            sheet.SetDefaultColumnStyle(1, style2);

            // Create a header row
            IRow headerRow = sheet.CreateRow(0);
            ICell headerCell0 = headerRow.CreateCell(0);
            ICell headerCell1 = headerRow.CreateCell(1);
            // Header cells get their own style
            ICellStyle headerStyle = wb.CreateCellStyle();
            headerStyle.FillForegroundColor = IndexedColors.Green.Index;
            headerStyle.FillPattern = FillPattern.SolidForeground;
            headerCell0.CellStyle = headerStyle;
            headerCell1.CellStyle = headerStyle;

            // Create data rows
            for (int rowIdx = 1; rowIdx <= 5; rowIdx++)
            {
                IRow dataRow = sheet.CreateRow(rowIdx);
                ICell cell0 = dataRow.CreateCell(0);
                ICell cell1 = dataRow.CreateCell(1);
                cell0.SetCellValue("Value" + rowIdx);
                cell1.SetCellValue("Value" + rowIdx);

                // Verify that the default column style is applied
                ClassicAssert.AreEqual(IndexedColors.Red.Index,
                    cell0.CellStyle.FillForegroundColor,
                    "Cell at row " + rowIdx + ", col 0 should have red fill (column default style)");
                ClassicAssert.AreEqual(IndexedColors.Blue.Index,
                    cell1.CellStyle.FillForegroundColor,
                    "Cell at row " + rowIdx + ", col 1 should have blue fill (column default style)");
            }

            // Header row cells should still have their own style (not overwritten)
            ClassicAssert.AreEqual(IndexedColors.Green.Index,
                headerCell0.CellStyle.FillForegroundColor,
                "Header cell col 0 should retain its own style");
            ClassicAssert.AreEqual(IndexedColors.Green.Index,
                headerCell1.CellStyle.FillForegroundColor,
                "Header cell col 1 should retain its own style");

            wb.Close();
        }

        [Test]
        public void TestDefaultColumnStyleWithRowStyleOverrides()
        {
